import type { HskEntry, VocabularyWord, Radical } from "@/types";
import { toPinyin, toPinyinPlain } from "./pinyin";

// ─── Static dataset ───────────────────────────────────────────────────────────
// Generated by: pnpm build:dataset  (scripts/build-dataset.mjs)
// Contains all HSK 1-7 words with pre-translated Vietnamese meanings.
import rawData from "@/data/hsk-processed.json";

const wordPool: HskEntry[] = rawData as HskEntry[];

export function fetchWordPool(): HskEntry[] {
  return wordPool;
}

