export function getRadicals(hanzi: string): Radical[] {
  const chars = [...hanzi];
  const results: Radical[] = [];
  const seen = new Set<string>();
  for (const char of chars) {
    if (seen.has(char)) continue;
    seen.add(char);
    const info = RADICAL_MAP[char];
    if (info) results.push({ char, meaning: info.meaning, pinyin: info.pinyin });
  }
  return results;
}

// ─── Build a full VocabularyWord from a static HskEntry ───────────────────────
export function buildVocabWord(entry: HskEntry, id: string): VocabularyWord {
  const pinyinResolved = entry.pinyin || toPinyin(entry.hanzi);
  const pinyinPlain = toPinyinPlain(entry.hanzi);
  const radicals = getRadicals(entry.hanzi);

  return {
    id,
    hanzi: entry.hanzi,
    pinyin: pinyinResolved,
    pinyinPlain,
    vietnamese: entry.vietnamese,
    english: entry.english,
    radicals,
    hskLevel: entry.hsk,
  };
}
